+fn replace_snapshot_with_rebuilt_path(
+    rebuilt_path: &Path,
+    snapshot_path: &Path,
+    backup_path: &Path,
+) -> Result<(), ShareError> {
+    std::fs::rename(snapshot_path, backup_path).map_err(|error| {
+        ShareError::Io(std::io::Error::other(format!(
+            "failed to stage existing snapshot for replacement: {error}"
+        )))
